def is_capital_offense(crime):
    capital_crimes = {
        'murder', 'drug trafficking', 'treason', 'acts of terrorism',
        'waging war against the King', 'rape resulting in death'
    }
    return crime.lower() in capital_crimes

# Example usage:
print(is_capital_offense('Murder'))  # Output: True
print(is_capital_offense('Theft'))   # Output: False
